//Initialize flow variables

flow.set("cs_errors", 0)            //Zero number of checksum errors
                                    //Also set to zero as part of the Power On sequence
flow.set("wrap_errors", 0)          //Zero number of wrap around errors                        

//CSV Logging initialization
flow.set("logging_state","off");    //Initial CSV logging state (do not chnage)
flow.set("logging_rate",20);        //Logging rate (# poll intervals to snapshot log data)
flow.set("logging_i",20);           //Initial counter (do not chnage)


//flow.set("overtemp_exciter_shutdown", ) Legacy and can likely be removed. Commenting out for the moment.


/*
The SPE can be set to display temperature in Celsius or Fahrenheit. Data
returned from the SPE via the serial USB interface are unit-less and
there is no way for Node Red to determine the temperature unit selected.

The unit (C or F) selected in the SPE Node Red flow must match the units (C or F) 
selected on the SPE setup menu on the amplifier itself.

For Those that would like to display units in degrees Fahrenheit, ensure the SPE 
is configured to report temperature in F, comment out the first line (Celsius) 
and uncomment out the second line (Fahrenheit).

The purpose of the selection below is to 1) display "C" or "F" on the gauges and 
2) set appropriate min, seg1, seg2 and max limits for the gauges. 

The flow always reports the numeric temperature provided by the SPE with no 
conversion (C to F or F to C) on the temperature itself.

Per Gianfranco's (I0ZY) email to the speexpertamps dated 10 January 2024:
  Regarding the positioning of the temperature sensor, just open the amplifier
  and one will see that it is located on the copper very close to the LDMOS.

  The SW manages the temperature in the following way:
  - In MAX when 75 °C is reached it automatically switches to MID.
  - In MID when 76 °C is reached it automatically switches to LOW.
  - In LOW when 77 °C is reached it automatically switches to STBY.
  As one can see, the SW is very protective (in some competitive amps the threshold is 
  much higher).

*/
flow.set("temperature_units" , "C");
//flow.set("temperature_units" , "F");

flow.set("temperature_guage_min" , 25);
flow.set("temperature_guage_seg1", 50);
flow.set("temperature_guage_seg2", 60);
flow.set("temperature_guage_max" , 65);

if (flow.get("temperature_units") == "F") {
    flow.set("temperature_guage_min" , 32 + (9*flow.get("temperature_guage_min" ))/5);
    flow.set("temperature_guage_seg1", 32 + (9*flow.get("temperature_guage_seg1"))/5);
    flow.set("temperature_guage_seg2", 32 + (9*flow.get("temperature_guage_seg2"))/5);
    flow.set("temperature_guage_max" , 32 + (9*flow.get("temperature_guage_max" ))/5);
    }
/*
The flow can, with the appropriate nodes enabled, initiate a link out message
to an exciter flow of the user's choosing. By default, those nodes are disabled
and the overtemp shutdown limit trigger is set to the gauge's maximum temperature.
*/


flow.set("overtemperature_active"           , false);
flow.set("overtemperature_state"            , "normal");
flow.set("set_mode_enabled"                 , true);                //Ability to change modes (standby/operate)
flow.set("force_mode_standby"               , false);


/*Set the Overtemperature value and action
    Overtemperature threshold is the begining of the gauge Max vaue (top of the red)
    overtemperature_action
        none
        spe_standby
        exciter_rx (link to third party flow)
        both

    overtemperature_state
        normal              no action pending
        cooling             Cooling waiting for temperature to normalize (disable transition to Operate)
        overtemp            Overtemp and waiting for Rx mode to switch to standby thereby avoiding hot switching

Note: To avoid hot switching, if the SPE is in transmit mode, the overtemperature action will take effect
      when the unit returns to receive mode to avoid hot switching

*/
//
//Overtemperature behavior parameters================================================================================
//Users should customize overtemperature parameters here:============================================================
//------------------------------------------------------------------------------------
//User settable overtemperature threshold (defaults to the flow variable "temperature_guage_max" set above)
flow.set("overtemperature_threshold", flow.get("temperature_guage_max"));  //Default is top of the red area
                                                                            //Numeric degrees in same units (C or F)
                                                                            //as SPE reports
//flow.set("overtemperature_threshold", 35);     //Serves 2 purposes:
                                                  //1) For overtemperature action testing. Set a low threshold
                                                  //   ensuring you use consistent units (C or F) om the setting
                                                  //2) To set an alternate overtemperature threashhold than
                                                  //    temperature_guage_max

//------------------------------------------------------------------------------------
//User settable Actions (select one of the four)
  flow.set("overtemperature_action", "none"             );  //default, do not comment out
                                                            //if other action desired, uncomment it to override
                                                            //the default
//flow.set("overtemperature_action", "spe_standby"      );
//flow.set("overtemperature_action", "exciter_rx"       );
//flow.set("overtemperature_action", "both"             );
//==================================================================================================================

//Diagnostic parameters reserved for Ron, WB2WGH (Please do NOT change)=============================================
//------------------------------------------------------------------------------------
//Polling lockout allows software driven menu traversal to disable normal flow serial 
//port polling to avoid any possible interaction. Initialize as false
flow.set("polling_lockout", false)

//------------------------------------------------------------------------------------
//The following are not intended to be changed by users. They
//are intended to simulate situations to facilitate testing
//of the flow. Please do not change them.
//
//Remember to uncomment out the sensor (Lower, Upper or Combiner) in the "Maximum Sensor Temperature" function node
//
flow.set("diag_sim_overtemp",false);
//flow.set("diag_sim_overtemp",true);
//==================================================================================================================

return msg;

/*
The drive for validting checksum was implementation of the Exciter Drive Level code. 
Without checksum validation, bogus data could enter the drive level code and result
in potential excessive drive level if someone leverated that option. Hence checksum
validation.

This checksum validation is authored to accomodate varying length packets. Having
said that, the only packets that will ever get past the SPE USB query will be 75
byte packets given some packets (status) are CR LF terminated and other packets
(commands) are not. Without consitent terminators, the hack was to terminate the
read after 75 byte packets from status queries. Other packets should time out.

The logic is here should it ever by required.


*/

var calc_cs=0;

for (let i = 4 ; i < 4+msg.payload[3]; i++) {
    calc_cs = calc_cs + msg.payload[i];
}
calc_cs_0 = calc_cs%256;
calc_cs_1 = Math.floor(calc_cs/256);

msg_cs_0 = msg.payload[4+msg.payload[3]+0];
msg_cs_1 = msg.payload[4+msg.payload[3]+1];

valid_cs = (calc_cs_0 == msg_cs_0) && (calc_cs_1 == msg_cs_1);
if (!valid_cs) {
    flow.set("cs_errors", flow.get("cs_errors")+1);
}

//msg.raw = [valid_cs , calc_cs , calc_cs_0, calc_cs_1,msg_cs_0 , msg_cs_1];
msg.status = valid_cs;
return msg;

/*
Detect if a wraparound condition exists in the packet 
    aa aa aa .... 0d 0a         -> Good packet, no wraparound
    aa aa ....... 0d 0a aa      -> Bad packet, wraparound

msg.status = true  if a wraparound condition exists
msg.status = false if no wraparound condition exists

*/
msg.status = !(
    (msg.payload[0]  == 0xAA) &&
    (msg.payload[1]  == 0xAA) &&
    (msg.payload[2]  == 0xAA) &&
    (msg.payload[74] == 0x0D) &&
    (msg.payload[75] == 0x0A)
    );
if (msg.status) {
        flow.set("wrap_errors", flow.get("wrap_errors")+1);
}
return msg;

var p = msg.payload;
var cmd;
switch (p) {
  case 'ON_SPE':
    msg.payload = 'poweron';
    msg.topic = 'spe_poweron';
    return msg;
  case 'MODE': cmd = Buffer.from([85, 85, 85, 1, 13, 13]); break;
  case 'TUNE': cmd = Buffer.from([85, 85, 85, 1, 9, 9]); break;
  case 'INPUT': cmd = Buffer.from([85, 85, 85, 1, 1, 1]); break;
  case 'ANTENNA': cmd = Buffer.from([85, 85, 85, 1, 4, 4]); break;
  case 'PWRLVL': cmd = Buffer.from([85, 85, 85, 1, 11, 11]); break;
  case 'BL_ON': cmd = Buffer.from([85, 85, 85, 1, 0x82, 0x82]); break;
  case 'BL_OFF': cmd = Buffer.from([85, 85, 85, 1, 0x83, 0x83]); break;
  case 'L_MINUS': cmd = Buffer.from([85, 85, 85, 1, 0x05, 0x05]); break;
  case 'L_PLUS': cmd = Buffer.from([85, 85, 85, 1, 0x06, 0x06]); break;
  case 'C_MINUS': cmd = Buffer.from([85, 85, 85, 1, 0x07, 0x07]); break;
  case 'C_PLUS': cmd = Buffer.from([85, 85, 85, 1, 0x08, 0x08]); break;
  case 'LEFT': cmd = Buffer.from([85, 85, 85, 1, 0x0f, 0x0f]); break;
  case 'RIGHT': cmd = Buffer.from([85, 85, 85, 1, 0x10, 0x10]); break;
  case 'SET': cmd = Buffer.from([85, 85, 85, 1, 0x11, 0x11]); break;
  case 'DISPLAY': cmd = Buffer.from([85, 85, 85, 1, 0x0c, 0x0c]); break;
  case 'BAND_MINUS': cmd = Buffer.from([85, 85, 85, 1, 0x02, 0x02]); break;
  case 'BAND_PLUS': cmd = Buffer.from([85, 85, 85, 1, 0x03, 0x03]); break;
  case 'OFF_SPE': cmd = Buffer.from([85, 85, 85, 1, 10, 10]); break;
  case 'BANK':
    msg.payload = 'BANK_TOGGLE';
    return msg;
  case 'LOGGING':
    msg.payload = 'LOGGING_TOGGLE';
    return msg;
  case 'FAN_QUIET':
    msg.payload = 'FAN_QUIET';
    return msg;
  case 'FAN_NORMAL':
    msg.payload = 'FAN_NORMAL';
    return msg;
  default: return null;
}
msg.payload = cmd;
return msg;

// Connect this node to your existing SPE CSV output (after the csv node)
// It converts the SPE col1..col20 object into the flat payload
// the new SPE template expects.
var p = msg.payload;
if(!p || !p.col2) return null;

var bandMap = {0:'160M',1:'80M',2:'60M',3:'40M',4:'30M',5:'20M',6:'17M',7:'15M',8:'12M',9:'10M',10:'6M',11:'4M'};
var pwrMap  = {L:'Low', M:'Middle', H:'Maximum'};

msg.payload = {
  model:    p.col2 || '—',
  mode:     p.col3==='S'?'Standby':'Operate',
  rxtx:     p.col4==='T'?'TRANSMIT':'RECEIVE',
  bank:     p.col5 || '—',
  input:    p.col6 || '—',
  band:     bandMap[parseInt(p.col7,10)] || '—',
  txant:    p.col8 || '—',
  rxant:    p.col9 || '—',
  pwrlvl:   pwrMap[p.col10] || p.col10 || '—',
  pwr:      parseFloat(p.col11)*1 || 0,
  pwrMax:   1500,
  atuswr:   parseFloat(p.col12) || 1,
  antswr:   parseFloat(p.col13) || 1,
  vpa:      parseFloat(p.col14) || 0,
  ipa:      parseFloat(p.col15) || 0,
  tempUpper: parseFloat(p.col16) || 0,
  tempLower: parseFloat(p.col17) || 0,
  tempComb:  parseFloat(p.col18) || 0,
  warnings:  p.col19==='N'?'No Warnings':(p.col19||'—'),
  alarms:    p.col20==='N'?'No Alarms':(p.col20||'—'),
  usb:  true,
  sync: true
};
return msg;

var hdg = 0;
if(typeof msg.payload === 'object' && msg.payload.heading !== undefined){
    hdg = parseFloat(msg.payload.heading);
} else {
    hdg = parseFloat(msg.payload);
}
if(isNaN(hdg)) return null;

var cx = 110, cy = 110;
var rad = (hdg - 90) * Math.PI / 180;
var r = 98;
var x2 = (cx + r * Math.cos(rad)).toFixed(1);
var y2 = (cy + r * Math.sin(rad)).toFixed(1);

var bx = cx + 70 * Math.cos(rad);
var by = cy + 70 * Math.sin(rad);
var lx = (bx - 8 * Math.sin(rad)).toFixed(1);
var ly = (by + 8 * Math.cos(rad)).toFixed(1);
var rx = (bx + 8 * Math.sin(rad)).toFixed(1);
var ry = (by - 8 * Math.cos(rad)).toFixed(1);

var updates = [
    {command: 'update_attribute', elementId: 'rot-actual', attributeName: 'x2', attributeValue: x2},
    {command: 'update_attribute', elementId: 'rot-actual', attributeName: 'y2', attributeValue: y2},
    {command: 'update_attribute', elementId: 'rot-arrow', attributeName: 'points', attributeValue: x2+','+y2+' '+lx+','+ly+' '+rx+','+ry},
    {command: 'update_text', elementId: 'rot-hdg-txt', textContent: Math.round(hdg)+'°'}
];

// Check if reached target - hide line after 3s
var target = flow.get('target_hdg');
if(target !== undefined && Math.abs(hdg - target) <= 3){
    flow.set('target_hdg', undefined);
    // 3s delay then hide
    setTimeout(function(){
        node.send({payload: [{
            command: 'update_attribute', elementId: 'rot-target',
            attributeName: 'opacity', attributeValue: '0'
        }]});
    }, 3000);
}

msg.payload = updates;
return msg;

var cx = 110, cy = 110;
if(!msg.event || msg.elementId !== 'clickzone') return [null, null];
var dx = msg.event.svgX - cx;
var dy = msg.event.svgY - cy;
if(Math.sqrt(dx*dx + dy*dy) > 103) return [null, null];
var angle = Math.atan2(dy, dx) * 180 / Math.PI;
var hdg = Math.round((angle + 90 + 360) % 360);
flow.set('target_hdg', hdg);
var work = ('00' + hdg).slice(-3);
var cmdMsg = {payload: 'AP1' + work + '\r'};
var rad = (hdg - 90) * Math.PI / 180;
var x2 = (cx + 98 * Math.cos(rad)).toFixed(1);
var y2 = (cy + 98 * Math.sin(rad)).toFixed(1);
var svgMsg = {payload: [
    {command: 'update_attribute', elementId: 'rot-target', attributeName: 'x2', attributeValue: x2},
    {command: 'update_attribute', elementId: 'rot-target', attributeName: 'y2', attributeValue: y2},
    {command: 'update_attribute', elementId: 'rot-target', attributeName: 'opacity', attributeValue: '0.7'}
]};
// Fallback: hide after 5 min if stalled
var t = context.get('t');
if(t) clearTimeout(t);
context.set('t', setTimeout(function(){
    flow.set('target_hdg', undefined);
    node.send([null, {payload: [{command:'update_attribute', elementId:'rot-target', attributeName:'opacity', attributeValue:'0'}]}]);
}, 300000));
return [cmdMsg, svgMsg];

var hdg = parseInt(msg.payload);
var work = ('00' + msg.payload).slice(-3);
var svgMsg;

if(msg.payload === 'stop' || msg.payload === 'STOP'){
    msg.payload = ';';
    flow.set('target_hdg', undefined);
    svgMsg = {payload: [{
        command: 'update_attribute', elementId: 'rot-target',
        attributeName: 'opacity', attributeValue: '0'
    }]};
    var t = context.get('t');
    if(t) clearTimeout(t);
} else if(!isNaN(hdg) && hdg >= 0 && hdg <= 359){
    msg.payload = 'AP1' + work + '\r';
    flow.set('target_hdg', hdg);
    var cx = 110, cy = 110;
    var rad = (hdg - 90) * Math.PI / 180;
    var x2 = (cx + 98 * Math.cos(rad)).toFixed(1);
    var y2 = (cy + 98 * Math.sin(rad)).toFixed(1);
    svgMsg = {payload: [
        {command: 'update_attribute', elementId: 'rot-target', attributeName: 'x2', attributeValue: x2},
        {command: 'update_attribute', elementId: 'rot-target', attributeName: 'y2', attributeValue: y2},
        {command: 'update_attribute', elementId: 'rot-target', attributeName: 'opacity', attributeValue: '0.7'}
    ]};
    // Fallback: hide after 5 min if rotator stalls
    var t = context.get('t');
    if(t) clearTimeout(t);
    context.set('t', setTimeout(function(){
        flow.set('target_hdg', undefined);
        node.send([null, {payload: [{command:'update_attribute', elementId:'rot-target', attributeName:'opacity', attributeValue:'0'}]}]);
    }, 300000));
} else {
    return [null, null];
}
return [msg, svgMsg];

var st = flow.get('flexState') || {};
var t = msg.topic || '';
var p = msg.payload;

// ── Discovery ──────────────────────────────────────────
if (p && typeof p === 'object' && p.model !== undefined) {
    st.model = p.model || st.model || '';
    st.callsign = p.callsign || st.callsign || '';
    if (p.gui_client_stations) st.clients = p.gui_client_stations.filter(Boolean);
    if (p.gui_client_ips) st.clientIPs = p.gui_client_ips.filter(Boolean);
    if (p.gui_client_handles && p.gui_client_stations) {
        st.clientHandleMap = {};
        p.gui_client_handles.forEach(function (h, i) {
            if (h && p.gui_client_stations[i]) {
                st.clientHandleMap[h] = p.gui_client_stations[i];
            }
        });
    }
}

// ── Interlock / TX state ───────────────────────────────
if (t === 'interlock' && p && p.state) {
    st.txstate = p.state;
}

// ── Transmit: RF + tune power ──────────────────────────
if (t === 'transmit' && p && typeof p === 'object') {
    if (typeof p.rfpower === 'number') st.rfpower = p.rfpower;
    if (typeof p.tunepower === 'number') st.tunepower = p.tunepower;
}

// ── Meters ─────────────────────────────────────────────
if (typeof p === 'string' || typeof p === 'number') {
    var v = parseFloat(p);
    if (/MAINFAN/.test(t)) st.fan = parseInt(p) || 0;
    if (/PATEMP/.test(t)) st.patemp = v;
    if (/13\.8A/.test(t)) st.pavolts = v;
    if (/13\.8B/.test(t)) st.involts = v;
    if (/MICPEAK/.test(t)) st.micpeak = v;
}

// ── Slice data ─────────────────────────────────────────
var sliceMatch = t.match(/^slice\/(\d+)$/);
if (sliceMatch && p && typeof p === 'object') {
    var idx = parseInt(sliceMatch[1]);
    var key = ['A', 'B', 'C', 'D'][idx];
    if (key) {
        if (!st.slices) st.slices = {};
        if (!st.slices[key]) st.slices[key] = {};
        if (typeof p.RF_frequency === 'number') st.slices[key].rawFreq = p.RF_frequency;
        if (typeof p.active === 'number') st.slices[key].active = p.active;
        if (typeof p.in_use === 'number') st.slices[key].in_use = p.in_use;
        if (typeof p.mode === 'string') st.slices[key].mode = p.mode;
        if (typeof p.tx === 'number') st.slices[key].tx = p.tx;
        if (typeof p.client_handle === 'string') st.slices[key].client = p.client_handle;
        // build handle map from slice data as fallback
        if (typeof p.client_handle === 'string' && typeof p.index_letter === 'string') {
            if (!st.clientHandleMap) st.clientHandleMap = {};
            // will be overwritten by discovery with real name if available
            if (!st.clientHandleMap[p.client_handle]) {
                st.clientHandleMap[p.client_handle] = p.client_handle;
            }
        }
    }
}

// ── Format freqs + build activeSlices ─────────────────
st.activeSlices = [];
if (st.slices) {
    ['A', 'B', 'C', 'D'].forEach(function (s) {
        var sl = st.slices[s];
        if (!sl) return;
        // format freq
        if (!sl.rawFreq) {
            sl.freq = '—';
        } else {
            var fixed = parseFloat(sl.rawFreq).toFixed(3);
            var parts = fixed.split('.');
            sl.freq = parts[0] + '.' + parts[1];
        }
        // build activeSlices from in_use slices
        if (sl.in_use === 1) {
            var clientName = '';
            if (st.clientHandleMap && sl.client) {
                clientName = st.clientHandleMap[sl.client] || sl.client;
            }
            st.activeSlices.push({
                slice: s,
                freq: sl.freq || '—',
                mode: sl.mode || '—',
                tx: sl.tx || 0,
                active: sl.active || 0,
                client: clientName
            });
        }
    });
}

// backward compat
if (st.activeSlices.length > 0) {
    st.activeFreq = st.activeSlices[0].freq;
    st.activeMode = st.activeSlices[0].mode;
}

flow.set('flexState', st);
msg.payload = st;
return msg;

var msg1,msg2,msg3,msg4
msg.c1 = "sub client all";   
msg.c2 = "sub slice all";
msg.c3 = "sub meter all";
msg.c4 = "sub tx all";
msg1 = {payload:msg.c1};
msg2 = {payload:msg.c2};
msg3 = {payload:msg.c3};
msg4 = {payload:msg.c4};
node.send(msg1);
node.send(msg2);
node.send(msg3);
node.send(msg4);
node.done();
return;

var Client_ID = flow.get("Client_ID","")
msg.payload = ["client bind client_id=" + Client_ID, "sub tx all"]
return msg;

var freq = msg.payload
freq = freq.toFixed(5)
var length = freq.toString().length
var hz = "", kz = "", mz = ""
if(freq < 9){
  if(length==1){hz="000";kz="000";mz=freq.toString().substr(0,1);}
  else if(length==3){hz="000";kz=freq.toString().substr(2,1)+"00";mz=freq.toString().substr(0,1);}
  else if(length==4){hz="000";kz=freq.toString().substr(2,2)+"0";mz=freq.toString().substr(0,1);}
  else if(length==5){hz="000";kz=freq.toString().substr(2,3);mz=freq.toString().substr(0,1);}
  else if(length==6){hz=freq.toString().substr(5,2)+"00";kz=freq.toString().substr(2,3);mz=freq.toString().substr(0,1);}
  else if(length==7){hz=freq.toString().substr(5,2)+"0";kz=freq.toString().substr(2,3);mz=freq.toString().substr(0,1);}
  else if(length==8){hz=freq.toString().substr(6,2)+"0";kz=freq.toString().substr(3,3);mz=freq.toString().substr(0,2);}
  else if(length==9){hz=freq.toString().substr(5,2)+"0";kz=freq.toString().substr(2,3);mz=freq.toString().substr(0,1);}
}
else if(freq>9&&freq<99){
  if(length==2){hz="000";kz="000";mz=freq.toString().substr(0,2);}
  else if(length==4){hz="000";kz=freq.toString().substr(3,1)+"00";mz=freq.toString().substr(0,2);}
  else if(length==5){hz="000";kz=freq.toString().substr(3,2)+"0";mz=freq.toString().substr(0,1);}
  else if(length==6){hz="000";kz=freq.toString().substr(3,3);mz=freq.toString().substr(0,2);}
