function fluxToClass(flux){
var label='',value=0,level=0
if(flux>=1.0e-4){value=Math.trunc((10*flux/1.0e-4)+1.0e-12)/10;label='X'+value.toFixed(1);level=value>=20?5:value>=10?4:3}
else if(flux>=1.0e-5){value=Math.trunc((10*flux/1.0e-5)+1.0e-12)/10;label='M'+value.toFixed(1);level=value>=5?2:1}
else if(flux>=1.0e-6){value=Math.trunc((10*flux/1.0e-6)+1.0e-12)/10;label='C'+value.toFixed(1);level=0}
else if(flux>=1.0e-7){value=Math.trunc((10*flux/1.0e-7)+1.0e-12)/10;label='B'+value.toFixed(1);level=0}
else{value=Math.trunc((10*flux/1.0e-8)+1.0e-12)/10;label='A'+value.toFixed(1);level=0}
return{label,level}
}
