// Tap into the raw NOAA scales JSON to extract numeric R/S/G values
// for the new dashboard panel (not HTML strings)
var p = msg.payload;

// Current (index 0)
var cur = p['0'] || p[0] || {};
msg._rsgCur = {
    R: parseInt(cur.R && cur.R.Scale) || 0,
    S: parseInt(cur.S && cur.S.Scale) || 0,
    G: parseInt(cur.G && cur.G.Scale) || 0
};

// 24-hour (last non-zero key)
var lastKey = Object.keys(p).filter(function(k){ return k !== '0'; }).slice(-1)[0];
var hr24 = (lastKey && p[lastKey]) || {};
msg._rsg24 = {
    R: parseInt(hr24.R && hr24.R.Scale) || 0,
    S: parseInt(hr24.S && hr24.S.Scale) || 0,
    G: parseInt(hr24.G && hr24.G.Scale) || 0
};

// Predicted (index 1)
var pred = p['1'] || p[1] || {};
var rMinor = pred.R && pred.R.MinorProb !== null ? Number(pred.R.MinorProb) : 0;
var rMajor = pred.R && pred.R.MajorProb !== null ? Number(pred.R.MajorProb) : 0;
var sProb  = pred.S && pred.S.Prob !== null ? Number(pred.S.Prob) : 0;
var gPred  = pred.G && pred.G.Scale !== null ? Number(pred.G.Scale) : 0;
// Simplify predicted R to a 0-5 equivalent scale
var rPred = 0;
if (rMajor >= 50) rPred = rMajor >= 90 ? 5 : rMajor >= 75 ? 4 : 3;
else if (rMinor >= 45) rPred = Math.abs(rMajor - rMinor) <= 5 ? 2 : 1;
msg._rsgPred = { R: rPred, S: sProb >= 50 ? 1 : 0, G: gPred };

return msg;

