// Handles ALL clusters feeding into this single node.
// A) Login  — detects 'login:' and replies VU24DX on same session
// B) Parse  — turns DX spot lines into SmartSDR spot add commands
// C) Dedup  — suppresses duplicate callsign+freq within 60 seconds
//             so multiple clusters don't spam the same spot
// ─────────────────────────────────────────────────────────────

var line = (msg.payload || '').trim();
var src  = msg.topic || 'unknown';   // which cluster this came from

// ── A) LOGIN ─────────────────────────────────────────────────
if (line.toLowerCase().includes('login:') ||
    line.toLowerCase().includes('please login')) {
