}

// ── Skip non-DX lines ─────────────────────────────────────────
if (!line.startsWith('DX de')) {
    node.status({ fill:'grey', shape:'ring', text: '['+src+'] '+line.substring(0,50) });
    return [ null, null ];
}

// ── B) PARSE ─────────────────────────────────────────────────
// Timestamp optional — handles spots with and without time
// var re = /^DX de\s+([A-Z0-9\/]+):\s+([\d.]+)\s+([A-Z0-9\/]+)\s*(.*?)\s*(\d{4}Z?)?\s*$/i;
var re = /^DX de\s+([A-Z0-9\/\-#]+):\s+([\d.]+)\s+([A-Z0-9\/\-#]+)\s*(.*?)\s*(\d{4}Z?)?\s*$/i;
var m  = line.match(re);
if (!m) {
    node.status({ fill:'yellow', shape:'dot', text:'no match: '+line.substring(0,45) });
    return [ null, null ];
}

var spotter = m[1].toUpperCase();
var freqKHz = parseFloat(m[2]);
var dxCall  = m[3].toUpperCase();
var comment = (m[4] || '').trim();
var freqMHz = (freqKHz / 1000).toFixed(6);

// ── C) DEDUP ─────────────────────────────────────────────────
// Key = callsign + frequency rounded to 1 kHz
// If same key seen within 60 seconds → drop (already sent by another cluster)
var dedup    = flow.get('dedup') || {};
var now      = Date.now();
var dedupKey = dxCall + '_' + Math.round(freqKHz);

if (dedup[dedupKey] && (now - dedup[dedupKey]) < 60000) {
    node.status({ fill:'grey', shape:'ring', text:'dup skip: '+dxCall+' ('+src+')' });
    return [ null, null ];   // duplicate — drop silently
}

// Record this spot
dedup[dedupKey] = now;

// Housekeeping: purge entries older than 120s to keep memory clean
Object.keys(dedup).forEach(function(k) {
    if (now - dedup[k] > 120000) delete dedup[k];
});
