// ── Mode detection ────────────────────────────────────────────
function getMode(khz, cmt) {
    var c = cmt.toUpperCase();
    if (c.match(/\bFT8\b/))  return 'Data';
    if (c.match(/\bFT4\b/))  return 'Data';
    if (c.match(/\bRTTY\b/)) return 'Data';
    if (c.match(/\bPSK\b/))  return 'Data';
    if (c.match(/\bDIGI\b/)) return 'Data';
    if (c.match(/\bDATA\b/)) return 'Data';
    if (c.match(/\bCW\b/))   return 'CW';
    if (c.match(/\bSSB\b/))  return (khz < 10000) ? 'LSB' : 'USB';
    if (c.match(/\bUSB\b/))  return 'USB';
    if (c.match(/\bLSB\b/))  return 'LSB';
    if (c.match(/\bAM\b/))   return 'AM';
    if (c.match(/\bFM\b/))   return 'FM';
    var ft8 = [1840,3573,7074,10136,14074,18100,21074,24915,28074,50313];
    for (var f=0; f<ft8.length; f++) {
        if (Math.abs(khz - ft8[f]) <= 3) return 'Data';
    }
    var cw = [[1800,1840],[3500,3600],[7000,7040],[10100,10150],
              [14000,14070],[18068,18110],[21000,21070],
              [24890,24920],[28000,28070]];
    for (var i=0; i<cw.length; i++) {
        if (khz >= cw[i][0] && khz <= cw[i][1]) return 'CW';
    }
    return (khz < 10000) ? 'LSB' : 'USB';
}

