function findKey(buf, key) {
    const kb = Buffer.from(key, 'ascii');
    for (let i = 0; i <= buf.length - kb.length; i++) {
        let match = true;
        for (let j = 0; j < kb.length; j++) {
            if (buf[i+j] !== kb[j]) { match = false; break; }
        }
        if (match) return i + kb.length;
    }
    return -1;
}

function readCoord(buf, startPos) {
    let minus = false, intStr = '', fracStr = '', hasDot = false, started = false;
    for (let i = startPos; i < Math.min(startPos+30, buf.length); i++) {
        const b = buf[i];
        const isBinary = (b < 0x20 || b >= 0x80);
        const isDigit  = (b >= 0x30 && b <= 0x39);
        if (!started) {
            if (b === 0x2D)    { minus = true; started = true; }
            else if (isDigit)  { intStr += String.fromCharCode(b); started = true; }
            else if (b === 0x2E) { hasDot = true; started = true; }
            else if (isBinary) continue;
        } else if (!hasDot) {
            if (isDigit)       intStr += String.fromCharCode(b);
            else if (b===0x2E) hasDot = true;
            else if (isBinary) continue;
            else break;
        } else {
            if (isDigit)                         fracStr += String.fromCharCode(b);
            else if (isBinary && fracStr.length < 4) continue;
            else break;
        }
    }
    if (!intStr && !fracStr) return null;
    const v = parseFloat((minus?'-':'')+(intStr||'0')+(hasDot?'.'+fracStr:''));
    return isNaN(v) ? null : v;
}

let latPos = findKey(buf, '"lat"'); if (latPos===-1) latPos = findKey(buf,'lat');
let lonPos = findKey(buf, '"lon"'); if (lonPos===-1) lonPos = findKey(buf,'lon');
if (latPos===-1 || lonPos===-1) return null;

const lat = readCoord(buf, latPos);
